INSERT INTO cities (county_id, name, slug, latitude, longitude, population) VALUES ((SELECT id FROM counties WHERE slug = 'winnebago-county' AND state_id = (SELECT id FROM states WHERE slug = 'illinois')), 'Rockford', 'rockford', 42.2711, -89.094, 148655) ON CONFLICT (county_id, slug) DO UPDATE SET latitude = excluded.latitude, longitude = excluded.longitude, population = excluded.population;
